// // This comment suggests that the counter will decrement on each clock edge when the enable signal is low.
module counter2bit(
    input clk,
    input reset,
    input enable,

    output reg [1:0] count
);

always @(posedge clk) begin
    if (reset)
        count <= 0;
    else if (enable)
        count <= count + 1;
end

endmodule
